                                `create_time` datetime NOT NULL COMMENT 'еҲӣе»әж—¶й—ҙ',
                                `update_time` datetime NOT NULL COMMENT 'жӣҙж–°ж—¶й—ҙ',
                                `create_user` bigint NOT NULL COMMENT 'еҲӣе»әдәә',
                                `update_user` bigint NOT NULL COMMENT 'дҝ®ж”№дәә',
                                `is_deleted` int NOT NULL DEFAULT 0 COMMENT 'жҳҜеҗҰеҲ йҷӨ',
                                PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'иҸңе“ҒеҸЈе‘іе…ізі»иЎЁ' ROW_FORMAT = DYNAMIC;

